      paragrafos: [],
      incisos: [{"id":"cpp:art-13-inc-I","numero":"I","texto":"fornecer às autoridades judiciárias as informações necessárias à instrução e julgamento dos processos;","alineas":[]},{"id":"cpp:art-13-inc-II","numero":"II","texto":"realizar as diligências requisitadas pelo juiz ou pelo Ministério Público;","alineas":[]},{"id":"cpp:art-13-inc-III","numero":"III","texto":"cumprir os mandados de prisão expedidos pelas autoridades judiciárias;","alineas":[]},{"id":"cpp:art-13-inc-IV","numero":"IV","texto":"representar acerca da prisão preventiva.","alineas":[]}],
