      paragrafos: [{"id":"cpp:art-137-p1","numero":"1","texto":"o Se esses bens forem coisas fungíveis e facilmente deterioráveis, proceder-se-á na forma do § 5o do art. 120.","alineas":[]},{"id":"cpp:art-137-p2","numero":"2","texto":"o Das rendas dos bens móveis poderão ser fornecidos recursos arbitrados pelo juiz, para a manutenção do indiciado e de sua família.","alineas":[]}],
