      id: "cpp:art-155",
      numero: "155",
      caput: "O juiz formará sua convicção pela livre apreciação da prova produzida em contraditório judicial, não podendo fundamentar sua decisão exclusivamente nos elementos informativos colhidos na investigação, ressalvadas as provas cautelares, não repetíveis e antecipadas.",
      paragrafos: [{"id":"cpp:art-155-púnico","numero":"único","texto":"Somente quanto ao estado das pessoas serão observadas as restrições estabelecidas na lei civil.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"O juiz formará sua convicção pela livre apreciação da prova produzida em contraditório judicial, não podendo fundamentar sua decisão exclusivamente nos elementos informativos colhidos na investigação, ressalvadas as provas cautelares, não repetíveis e antecipadas.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 11.690, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§único: Somente quanto ao estado das pessoas serão observadas as restrições estabelecidas na lei civil.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.690, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
