      historico: [{"versao":1,"texto":"Se o acusado não atender à intimação para o interrogatório, reconhecimento ou qualquer outro ato que, sem ele, não possa ser realizado, a autoridade poderá mandar conduzi-lo à sua presença.","redacaoDadaPor":{"lei":"Vide ADPF 395","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
