      historico: [{"versao":1,"texto":"O processo terá completada a sua formação quando realizada a citação do acusado. .","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"Inc. I: (revogado); .","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"Inc. II: (revogado). .","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§1: o Não sendo encontrado o acusado, será procedida a citação por edital. .","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":5,"texto":"§2: o (VETADO) .","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":6,"texto":"§3: o (VETADO) .","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":7,"texto":"§4: o Comparecendo o acusado citado por edital, em qualquer tempo, o processo observará o disposto nos arts. 394 e seguintes deste Código. .","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
