      historico: [{"versao":1,"texto":"Se o acusado, citado por edital, não comparecer, nem constituir advogado, ficarão suspensos o processo e o curso do prazo prescricional, podendo o juiz determinar a produção antecipada das provas consideradas urgentes e, se for o caso, decretar prisão preventiva, nos termos do disposto no art. 312.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 9.271, de 17.4.1996","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: o .","redacaoDadaPor":{"lei":"Revogado pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§2: o .","redacaoDadaPor":{"lei":"Revogado pela Lei nº 11.719, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
