      id: "cpp:art-378",
      numero: "378",
      caput: "A aplicação provisória de medida de segurança obedecerá ao disposto nos artigos anteriores, com as modificações seguintes:",
      paragrafos: [],
      incisos: [{"id":"cpp:art-378-inc-I","numero":"I","texto":"o juiz poderá aplicar, provisoriamente, a medida de segurança, de ofício, ou a requerimento do Ministério Público;","alineas":[]},{"id":"cpp:art-378-inc-II","numero":"II","texto":"a aplicação poderá ser determinada ainda no curso do inquérito, mediante representação da autoridade policial;","alineas":[]},{"id":"cpp:art-378-inc-III","numero":"III","texto":"a aplicação provisória de medida de segurança, a substituição ou a revogação da anteriormente aplicada poderão ser determinadas, também, na sentença absolutória;","alineas":[]},{"id":"cpp:art-378-inc-IV","numero":"IV","texto":"decretada a medida, atender-se-á ao disposto no Título V do Livro IV, no que for aplicável.","alineas":[]}],
