      id: "cpp:art-381",
      numero: "381",
      caput: "A sentença conterá:",
      paragrafos: [],
      incisos: [{"id":"cpp:art-381-inc-I","numero":"I","texto":"os nomes das partes ou, quando não possível, as indicações necessárias para identificá-las;","alineas":[]},{"id":"cpp:art-381-inc-II","numero":"II","texto":"a exposição sucinta da acusação e da defesa;","alineas":[]},{"id":"cpp:art-381-inc-III","numero":"III","texto":"a indicação dos motivos de fato e de direito em que se fundar a decisão;","alineas":[]},{"id":"cpp:art-381-inc-IV","numero":"IV","texto":"a indicação dos artigos de lei aplicados;","alineas":[]},{"id":"cpp:art-381-inc-V","numero":"V","texto":"o dispositivo;","alineas":[]},{"id":"cpp:art-381-inc-VI","numero":"VI","texto":"a data e a assinatura do juiz.","alineas":[]}],
      referencias: [],
