      paragrafos: [{"id":"cpp:art-394-p1","numero":"1","texto":"o O procedimento comum será ordinário, sumário ou sumaríssimo: .","alineas":[]},{"id":"cpp:art-394-p2","numero":"2","texto":"o Aplica-se a todos os processos o procedimento comum, salvo disposições em contrário deste Código ou de lei especial. .","alineas":[]},{"id":"cpp:art-394-p3","numero":"3","texto":"o Nos processos de competência do Tribunal do Júri, o procedimento observará as disposições estabelecidas nos arts. 406 a 497 deste Código. .","alineas":[]},{"id":"cpp:art-394-p4","numero":"4","texto":"o As disposições dos arts. 395 a 398 deste Código aplicam-se a todos os procedimentos penais de primeiro grau, ainda que não regulados neste Código. .","alineas":[]},{"id":"cpp:art-394-p5","numero":"5","texto":"o Aplicam-se subsidiariamente aos procedimentos especial, sumário e sumaríssimo as disposições do procedimento ordinário. .","alineas":[]}],
