      id: "cpp:art-399",
      numero: "399",
      caput: "Recebida a denúncia ou queixa, o juiz designará dia e hora para a audiência, ordenando a intimação do acusado, de seu defensor, do Ministério Público e, se for o caso, do querelante e do assistente. .",
      paragrafos: [{"id":"cpp:art-399-p1","numero":"1","texto":"o O acusado preso será requisitado para comparecer ao interrogatório, devendo o poder público providenciar sua apresentação. .","alineas":[]},{"id":"cpp:art-399-p2","numero":"2","texto":"o O juiz que presidiu a instrução deverá proferir a sentença. .","alineas":[]}],
