      referencias: [],
      historico: [{"versao":1,"texto":"Na audiência de instrução e julgamento, e, em especial, nas que apurem crimes contra a dignidade sexual, todas as partes e demais sujeitos processuais presentes no ato deverão zelar pela integridade física e psicológica da vítima, sob pena de responsabilização civil, penal e administrativa, cabendo ao juiz garantir o cumprimento do disposto neste artigo, vedadas:","redacaoDadaPor":{"lei":"Vide ADPF 1107","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"Inc. I: a manifestação sobre circunstâncias ou elementos alheios aos fatos objeto de apuração nos autos;","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.245, de 2021","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"Inc. II: a utilização de linguagem, de informações ou de material que ofendam a dignidade da vítima ou de testemunhas.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.245, de 2021","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
