    {
      tipo: "artigo" as const,
      id: "cpp:art-411",
      numero: "411",
      caput: "Na audiência de instrução, proceder-se-á à tomada de declarações do ofendido, se possível, à inquirição das testemunhas arroladas pela acusação e pela defesa, nesta ordem, bem como aos esclarecimentos dos peritos, às acareações e ao reconhecimento de pessoas e coisas, interrogando-se, em seguida, o acusado e procedendo-se o debate.",
      paragrafos: [{"id":"cpp:art-411-p1","numero":"1","texto":"o Os esclarecimentos dos peritos dependerão de prévio requerimento e de deferimento pelo juiz.","alineas":[]},{"id":"cpp:art-411-p2","numero":"2","texto":"o As provas serão produzidas em uma só audiência, podendo o juiz indeferir as consideradas irrelevantes, impertinentes ou protelatórias.","alineas":[]},{"id":"cpp:art-411-p3","numero":"3","texto":"o Encerrada a instrução probatória, observar-se-á, se for o caso, o disposto no art. 384 deste Código.","alineas":[]},{"id":"cpp:art-411-p4","numero":"4","texto":"o As alegações serão orais, concedendo-se a palavra, respectivamente, à acusação e à defesa, pelo prazo de 20 (vinte) minutos, prorrogáveis por mais 10 (dez).","alineas":[]},{"id":"cpp:art-411-p5","numero":"5","texto":"o Havendo mais de 1 (um) acusado, o tempo previsto para a acusação e a defesa de cada um deles será individual.","alineas":[]},{"id":"cpp:art-411-p6","numero":"6","texto":"o Ao assistente do Ministério Público, após a manifestação deste, serão concedidos 10 (dez) minutos, prorrogando-se por igual período o tempo de manifestação da defesa.","alineas":[]},{"id":"cpp:art-411-p7","numero":"7","texto":"o Nenhum ato será adiado, salvo quando imprescindível à prova faltante, determinando o juiz a condução coercitiva de quem deva comparecer.","alineas":[]},{"id":"cpp:art-411-p8","numero":"8","texto":"o A testemunha que comparecer será inquirida, independentemente da suspensão da audiência, observada em qualquer caso a ordem estabelecida no caput deste artigo.","alineas":[]},{"id":"cpp:art-411-p9","numero":"9","texto":"o Encerrados os debates, o juiz proferirá a sua decisão, ou o fará em 10 (dez) dias, ordenando que os autos para isso lhe sejam conclusos.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"Na audiência de instrução, proceder-se-á à tomada de declarações do ofendido, se possível, à inquirição das testemunhas arroladas pela acusação e pela defesa, nesta ordem, bem como aos esclarecimentos dos peritos, às acareações e ao reconhecimento de pessoas e coisas, interrogando-se, em seguida, o acusado e procedendo-se o debate.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: o Os esclarecimentos dos peritos dependerão de prévio requerimento e de deferimento pelo juiz.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§2: o As provas serão produzidas em uma só audiência, podendo o juiz indeferir as consideradas irrelevantes, impertinentes ou protelatórias.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§3: o Encerrada a instrução probatória, observar-se-á, se for o caso, o disposto no art. 384 deste Código.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":5,"texto":"§4: o As alegações serão orais, concedendo-se a palavra, respectivamente, à acusação e à defesa, pelo prazo de 20 (vinte) minutos, prorrogáveis por mais 10 (dez).","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":6,"texto":"§5: o Havendo mais de 1 (um) acusado, o tempo previsto para a acusação e a defesa de cada um deles será individual.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":7,"texto":"§6: o Ao assistente do Ministério Público, após a manifestação deste, serão concedidos 10 (dez) minutos, prorrogando-se por igual período o tempo de manifestação da defesa.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":8,"texto":"§7: o Nenhum ato será adiado, salvo quando imprescindível à prova faltante, determinando o juiz a condução coercitiva de quem deva comparecer.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":9,"texto":"§8: o A testemunha que comparecer será inquirida, independentemente da suspensão da audiência, observada em qualquer caso a ordem estabelecida no caput deste artigo.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":10,"texto":"§9: o Encerrados os debates, o juiz proferirá a sua decisão, ou o fará em 10 (dez) dias, ordenando que os autos para isso lhe sejam conclusos.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    }
