      id: "cpp:art-436",
      numero: "436",
      caput: "O serviço do júri é obrigatório. O alistamento compreenderá os cidadãos maiores de 18 (dezoito) anos de notória idoneidade.",
      paragrafos: [{"id":"cpp:art-436-p1","numero":"1","texto":"o Nenhum cidadão poderá ser excluído dos trabalhos do júri ou deixar de ser alistado em razão de cor ou etnia, raça, credo, sexo, profissão, classe social ou econômica, origem ou grau de instrução.","alineas":[]},{"id":"cpp:art-436-p2","numero":"2","texto":"o A recusa injustificada ao serviço do júri acarretará multa no valor de 1 (um) a 10 (dez) salários mínimos, a critério do juiz, de acordo com a condição econômica do jurado.","alineas":[]}],
