      referencias: [],
      historico: [{"versao":1,"texto":"Desacolhida a argüição de impedimento, de suspeição ou de incompatibilidade contra o juiz presidente do Tribunal do Júri, órgão do Ministério Público, jurado ou qualquer funcionário, o julgamento não será suspenso, devendo, entretanto, constar da ata o seu fundamento e a decisão.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 11.689, de 2008","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
