    {
      tipo: "artigo" as const,
      id: "cpp:art-541",
      numero: "541",
      caput: "Os autos originais de processo penal extraviados ou destruídos, em primeira ou segunda instância, serão restaurados.",
      paragrafos: [{"id":"cpp:art-541-p1","numero":"1","texto":"o Se existir e for exibida cópia autêntica ou certidão do processo, será uma ou outra considerada como original.","alineas":[]},{"id":"cpp:art-541-p2","numero":"2","texto":"o Na falta de cópia autêntica ou certidão do processo, o juiz mandará, de ofício, ou a requerimento de qualquer das partes, que:","alineas":[{"id":"cpp:art-541-p2-a","numero":"a","texto":"o escrivão certifique o estado do processo, segundo a sua lembrança, e reproduza o que houver a respeito em seus protocolos e registros;"},{"id":"cpp:art-541-p2-b","numero":"b","texto":"sejam requisitadas cópias do que constar a respeito no Instituto Médico-Legal, no Instituto de Identificação e Estatística ou em estabelecimentos congêneres, repartições públicas, penitenciárias ou cadeias;"},{"id":"cpp:art-541-p2-c","numero":"c","texto":"as partes sejam citadas pessoalmente, ou, se não forem encontradas, por edital, com o prazo de dez dias, para o processo de restauração dos autos."}]},{"id":"cpp:art-541-p3","numero":"3","texto":"o Proceder-se-á à restauração na primeira instância, ainda que os autos se tenham extraviado na segunda.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "cpp:art-542",
      numero: "542",
      caput: "No dia designado, as partes serão ouvidas, mencionando-se em termo circunstanciado os pontos em que estiverem acordes e a exibição e a conferência das certidões e mais reproduções do processo apresentadas e conferidas.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "cpp:art-543",
      numero: "543",
      caput: "O juiz determinará as diligências necessárias para a restauração, observando-se o seguinte:",
      paragrafos: [],
      incisos: [{"id":"cpp:art-543-inc-I","numero":"I","texto":"caso ainda não tenha sido proferida a sentença, reinquirir-se-ão as testemunhas podendo ser substituídas as que tiverem falecido ou se encontrarem em lugar não sabido;","alineas":[]},{"id":"cpp:art-543-inc-II","numero":"II","texto":"os exames periciais, quando possível, serão repetidos, e de preferência pelos mesmos peritos;","alineas":[]},{"id":"cpp:art-543-inc-III","numero":"III","texto":"a prova documental será reproduzida por meio de cópia autêntica ou, quando impossível, por meio de testemunhas;","alineas":[]},{"id":"cpp:art-543-inc-IV","numero":"IV","texto":"poderão também ser inquiridas sobre os atos do processo, que deverá ser restaurado, as autoridades, os serventuários, os peritos e mais pessoas que tenham nele funcionado;","alineas":[]},{"id":"cpp:art-543-inc-V","numero":"V","texto":"o Ministério Público e as partes poderão oferecer testemunhas e produzir documentos, para provar o teor do processo extraviado ou destruído.","alineas":[]}],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "cpp:art-544",
      numero: "544",
      caput: "Realizadas as diligências que, salvo motivo de força maior, deverão concluir-se dentro de vinte dias, serão os autos conclusos para julgamento.",
      paragrafos: [{"id":"cpp:art-544-púnico","numero":"único","texto":"No curso do processo, e depois de subirem os autos conclusos para sentença, o juiz poderá, dentro em cinco dias, requisitar de autoridades ou de repartições todos os esclarecimentos para a restauração.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "cpp:art-545",
      numero: "545",
      caput: "Os selos e as taxas judiciárias, já pagos nos autos originais, não serão novamente cobrados.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "cpp:art-546",
      numero: "546",
      caput: "Os causadores de extravio de autos responderão pelas custas, em dobro, sem prejuízo da responsabilidade criminal.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "cpp:art-547",
      numero: "547",
      caput: "Julgada a restauração, os autos respectivos valerão pelos originais.",
      paragrafos: [{"id":"cpp:art-547-púnico","numero":"único","texto":"Se no curso da restauração aparecerem os autos originais, nestes continuará o processo, apensos a eles os autos da restauração.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [],
    }
