      paragrafos: [{"id":"cpp:art-620-p1","numero":"1","texto":"o O requerimento será apresentado pelo relator e julgado, independentemente de revisão, na primeira sessão.","alineas":[]},{"id":"cpp:art-620-p2","numero":"2","texto":"o Se não preenchidas as condições enumeradas neste artigo, o relator indeferirá desde logo o requerimento.","alineas":[]}],
